import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as n,o as i,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/magnet-transfer.md","filePath":"fa/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"fa/Other/magnet-transfer.md"};function p(c,a,h,m,g,u){return i(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer، files را از magnet link download می‌کند و به‌صورت خودکار در cloud storage channel انتخاب‌شده upload می‌کند.</p><p>برای transfer کردن anime episodes، videos، archives و files مشابه مفید است. magnet link را paste کنید؛ ImgBed یک background download task می‌سازد. پس از پایان download، file در ImgBed upload می‌شود و final link در upload list ظاهر می‌شود.</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="کجا-استفاده-کنیم" tabindex="-1">کجا استفاده کنیم <a class="header-anchor" href="#کجا-استفاده-کنیم" aria-label="Permalink to &quot;کجا استفاده کنیم&quot;">​</a></h2><p>entry مربوط به magnet transfer در homepage upload area است.</p><p>magnet link را در input box paste کنید، <code>Transfer</code> را انتخاب کنید و سپس upload کنید.</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="پیش-از-اولین-استفاده" tabindex="-1">پیش از اولین استفاده <a class="header-anchor" href="#پیش-از-اولین-استفاده" aria-label="Permalink to &quot;پیش از اولین استفاده&quot;">​</a></h2><p>ابتدا magnet transfer را در admin panel configure کنید.</p><p>معمولاً نیاز دارید به:</p><ol><li>GitHub account برای اجرای download task.</li><li>cloud upload channel مثل Google Drive یا OneDrive.</li><li>target upload directory.</li><li>task timeout.</li></ol><p>پس از آماده شدن settings، به homepage برگردید و magnet link را paste کنید تا transfer شروع شود.</p><h2 id="upload-کردن-magnet-link" tabindex="-1">Upload کردن Magnet Link <a class="header-anchor" href="#upload-کردن-magnet-link" aria-label="Permalink to &quot;Upload کردن Magnet Link&quot;">​</a></h2><ol><li>magnet link را در homepage upload box paste کنید.</li><li>مطمئن شوید mode روی <code>Transfer</code> است.</li><li>upload را بزنید.</li><li>منتظر بمانید ImgBed magnet task را create کند.</li><li>پس از شروع task، از floating panel با نام <code>Magnet Tasks</code> در گوشه پایین راست، progress را بررسی کنید.</li></ol><p>download و upload ممکن است زمان‌بر باشند. speed به magnet resource، GitHub runtime environment و cloud storage channel انتخاب‌شده بستگی دارد.</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="پس-از-completion" tabindex="-1">پس از Completion <a class="header-anchor" href="#پس-از-completion" aria-label="Permalink to &quot;پس از Completion&quot;">​</a></h2><p>پس از complete شدن task، upload list نام file و link را نشان می‌دهد.</p><p>videos، video preview نشان می‌دهند؛ images، image preview نشان می‌دهند؛ و other files با regular file icon نمایش داده می‌شوند.</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>می‌توانید copy کنید:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>direct file access</td></tr><tr><td>Markdown</td><td>Markdown posts یا notes</td></tr><tr><td>HTML</td><td>web page code</td></tr><tr><td>BBCode</td><td>forums که BBCode پشتیبانی می‌کنند</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>magnet task panel در پایین راست، task count، task name، progress و final status را نشان می‌دهد.</p><p>وضعیت‌های رایج:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th></tr></thead><tbody><tr><td>Waiting</td><td>task ساخته شده و منتظر اجراست.</td></tr><tr><td>Downloading</td><td>magnet resource در حال download است.</td></tr><tr><td>Uploading</td><td>file download شده و در حال upload به cloud storage است.</td></tr><tr><td>Completed</td><td>upload موفق بوده و link قابل copy است.</td></tr><tr><td>Failed</td><td>task با موفقیت تمام نشده. message را بررسی کنید و دوباره تلاش کنید.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>اگر magnet link چند file داشته باشد، ImgBed برای display معمولاً main completed file را اولویت می‌دهد.</li><li>large files زمان بیشتری می‌گیرند. پیش از refresh کردن page صبر کنید task تمام شود.</li><li>اگر magnet resource peers در دسترس نداشته باشد، ممکن است بسیار کند یا fail شود.</li><li>اگر cloud account quota تمام شده باشد، authorization expire شده باشد یا upload directory اشتباه باشد، task ممکن است fail شود.</li><li>video preview ممکن است چند ثانیه بعد از upload complete طول بکشد.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="بعد-از-paste-کردن-magnet-link-هیچ-چیزی-شروع-نمی‌شود" tabindex="-1">بعد از Paste کردن Magnet Link هیچ چیزی شروع نمی‌شود <a class="header-anchor" href="#بعد-از-paste-کردن-magnet-link-هیچ-چیزی-شروع-نمی‌شود" aria-label="Permalink to &quot;بعد از Paste کردن Magnet Link هیچ چیزی شروع نمی‌شود&quot;">​</a></h3><p>مطمئن شوید magnet transfer در admin panel enabled است و GitHub account و cloud channel قابل استفاده انتخاب شده‌اند.</p><h3 id="download-همیشه-کند-است" tabindex="-1">Download همیشه کند است <a class="header-anchor" href="#download-همیشه-کند-است" aria-label="Permalink to &quot;Download همیشه کند است&quot;">​</a></h3><p>magnet speed به خود resource بستگی دارد. اگر peers در دسترس نباشند، download بسیار کند یا غیرممکن می‌شود.</p><h3 id="بعد-از-upload،-preview-دیده-نمی‌شود" tabindex="-1">بعد از Upload، Preview دیده نمی‌شود <a class="header-anchor" href="#بعد-از-upload،-preview-دیده-نمی‌شود" aria-label="Permalink to &quot;بعد از Upload، Preview دیده نمی‌شود&quot;">​</a></h3><p>اول مطمئن شوید file link باز می‌شود. video files ممکن است کمی زمان برای load شدن در browser بخواهند، یا می‌توانید link را مستقیم باز کنید.</p><h3 id="اگر-task-fail-شد-چه-چیزهایی-را-بررسی-کنم؟" tabindex="-1">اگر Task Fail شد چه چیزهایی را بررسی کنم؟ <a class="header-anchor" href="#اگر-task-fail-شد-چه-چیزهایی-را-بررسی-کنم؟" aria-label="Permalink to &quot;اگر Task Fail شد چه چیزهایی را بررسی کنم؟&quot;">​</a></h3><p>valid بودن magnet link، درست کار کردن cloud channel و صحیح بودن upload directory را بررسی کنید. سپس task را دوباره submit کنید.</p>',38)])])}const _=n(s,[["render",p]]);export{b as __pageData,_ as default};
